// Routes all manager commands to managerService.handleManagerCommand()
// Supports: /orders /stock /tasks /purchases /calendar /client /price_review /setup_check etc.
const { handleManagerCommand } = require('./app/js/manager/managerService.js');
const { sendTelegramMessage } = require('./app/js/tasks/notificationService.js');
const chatId = String($json.body?.message?.chat?.id);
const text = $json.body?.message?.text || '';
const callbackData = $json.body?.callback_query?.data || '';
const [command, ...args] = (text || `/${callbackData}`).trim().split(/\s+/);
try {
  const result = await handleManagerCommand(command, args);
  const responseText = typeof result === 'string' ? result : (result?.text || JSON.stringify(result, null, 2));
  await sendTelegramMessage(chatId, responseText, { keyboard: result?.keyboard });
} catch (err) {
  await sendTelegramMessage(chatId, `❌ Помилка: ${err.message}`);
}
return [];
